import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, Tuple

def decode_jwt(token: str, secret: Optional[str] = None, verify: bool = False, 
               algorithms: list = None) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and optionally verify a JWT token for debugging purposes.
    
    Args:
        token: JWT token string
        secret: Secret key for verification (optional)
        verify: Whether to verify signature (default: False for debugging)
        algorithms: List of allowed algorithms (default: ['HS256', 'RS256'])
    
    Returns:
        Tuple of (decoded_payload, metadata)
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512']
    
    metadata = {
        'valid': False,
        'expired': False,
        'error': None,
        'header': {},
        'issued_at': None,
        'expires_at': None,
        'not_before': None,
        'time_until_expiry': None
    }
    
    try:
        # Decode header without verification
        metadata['header'] = jwt.get_unverified_header(token)
        
        if verify and secret:
            # Verify and decode
            decoded = jwt.decode(token, secret, algorithms=algorithms)
            metadata['valid'] = True
        else:
            # Decode without verification
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
            if not verify:
                metadata['valid'] = None  # Unknown, not verified
        
        # Extract timing information
        current_time = datetime.utcnow()
        
        if 'iat' in decoded:
            metadata['issued_at'] = datetime.fromtimestamp(decoded['iat'])
        
        if 'exp' in decoded:
            exp_time = datetime.fromtimestamp(decoded['exp'])
            metadata['expires_at'] = exp_time
            time_diff = (exp_time - current_time).total_seconds()
            metadata['time_until_expiry'] = time_diff
            
            if time_diff < 0:
                metadata['expired'] = True
                if verify:
                    metadata['valid'] = False
        
        if 'nbf' in decoded:
            metadata['not_before'] = datetime.fromtimestamp(decoded['nbf'])
        
    except jwt.ExpiredSignatureError:
        metadata['error'] = 'Token has expired'
        metadata['expired'] = True
        metadata['valid'] = False
        # Try to decode without verification to get payload
        try:
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
            if 'exp' in decoded:
                metadata['expires_at'] = datetime.fromtimestamp(decoded['exp'])
        except:
            decoded = {}
            
    except jwt.InvalidSignatureError:
        metadata['error'] = 'Invalid signature'
        metadata['valid'] = False
        try:
            decoded = jwt.decode(token, options={"verify_signature": False}, algorithms=algorithms)
        except:
            decoded = {}
            
    except jwt.DecodeError as e:
        metadata['error'] = f'Decode error: {str(e)}'
        metadata['valid'] = False
        decoded = {}
        
    except jwt.InvalidTokenError as e:
        metadata['error'] = f'Invalid token: {str(e)}'
        metadata['valid'] = False
        decoded = {}
        
    except Exception as e:
        metadata['error'] = f'Unexpected error: {str(e)}'
        metadata['valid'] = False
        decoded = {}
    
    return decoded, metadata


def print_jwt_info(token: str, secret: Optional[str] = None, verify: bool = False):
    """
    Print formatted JWT token information for debugging.
    """
    print("=" * 80)
    print("JWT TOKEN ANALYSIS")
    print("=" * 80)
    
    decoded, metadata = decode_jwt(token, secret, verify)
    
    # Print header
    print("\nHEADER:")
    print(json.dumps(metadata['header'], indent=2))
    
    # Print payload
    print("\nPAYLOAD:")
    print(json.dumps(decoded, indent=2, default=str))
    
    # Print metadata
    print("\nMETADATA:")
    print(f"  Valid: {metadata['valid']}")
    print(f"  Expired: {metadata['expired']}")
    
    if metadata['error']:
        print(f"  Error: {metadata['error']}")
    
    if metadata['issued_at']:
        print(f"  Issued At: {metadata['issued_at']}")
    
    if metadata['expires_at']:
        print(f"  Expires At: {metadata['expires_at']}")
    
    if metadata['time_until_expiry'] is not None:
        if metadata['time_until_expiry'] > 0:
            print(f"  Time Until Expiry: {metadata['time_until_expiry']:.0f} seconds")
        else:
            print(f"  Expired: {abs(metadata['time_until_expiry']):.0f} seconds ago")
    
    if metadata['not_before']:
        print(f"  Not Before: {metadata['not_before']}")
    
    print("=" * 80)
    
    return decoded, metadata


def inspect_jwt(token: str, secret: Optional[str] = None):
    """
    Quick inspection function - returns decoded payload and prints info.
    """
    return print_jwt_info(token, secret, verify=bool(secret))